class TradingService: ObservableObject {
    static let shared = TradingService()
    
    @Published var portfolio: Portfolio?
    @Published var recentTrades: [Trade] = []
    @Published var isExecutingTrade = false
    
    private let apiManager = SecureAPIManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    private init() {}
    
    func fetchPortfolio() async throws {
        let portfolio: Portfolio = try await apiManager.request("/portfolio")
        await MainActor.run {
            self.portfolio = portfolio
        }
    }
    
    func fetchRecentTrades() async throws {
        let trades: [Trade] = try await apiManager.request("/trades/recent")
        await MainActor.run {
            self.recentTrades = trades
        }
    }
    
    func executeTrade(symbol: String, type: TradeType, quantity: Double, price: Double? = nil) async throws -> TradeResponse {
        await MainActor.run {
            isExecutingTrade = true
        }
        
        defer {
            Task { @MainActor in
                isExecutingTrade = false
            }
        }
        
        let request = TradeRequest(symbol: symbol, type: type, quantity: quantity, price: price)
        let response: TradeResponse = try await apiManager.request("/trades/execute", method: "POST", body: request)
        
        await MainActor.run {
            self.portfolio = response.portfolio
            self.recentTrades.insert(response.trade, at: 0)
        }
        
        return response
    }
    
    func cancelTrade(tradeId: String) async throws {
        let _: Trade = try await apiManager.request("/trades/\(tradeId)/cancel", method: "POST")
        try await fetchRecentTrades()
    }
    
    func getQuote(symbol: String) async throws -> Stock {
        return try await apiManager.request("/stocks/\(symbol)/quote")
    }
}

