              let quantityText = quantityTextField.text,
              let quantity = Double(quantityText) else {
            estimatedCostLabel.text = "Estimated: $0.00"
            return
        }
        
        let total = quantity * stock.currentPrice
        let prefix = tradeType == .buy ? "Est. Cost: " : "Est. Proceeds: "
        estimatedCostLabel.text = prefix + formatCurrency(total)
    }
    
    @objc private func executeTrade() {
        guard let stock = stock,
              let quantityText = quantityTextField.text,
              let quantity = Double(quantityText),
              quantity > 0 else {
            showAlert(title: "Invalid Quantity", message: "Please enter a valid quantity.")
            return
        }
        
        let alertTitle = tradeType == .buy ? "Confirm Buy" : "Confirm Sell"
        let alertMessage = "\(tradeType.rawValue.capitalized) \(quantity) shares of \(stock.symbol) at \(formatCurrency(stock.currentPrice))?"
        
        let alert = UIAlertController(title: alertTitle, message: alertMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Confirm", style: .default) { [weak self] _ in
            self?.performTrade(quantity: quantity)
        })
        present(alert, animated: true)
    }
    
    private func performTrade(quantity: Double) {
        guard let stock = stock else { return }
        
        activityIndicator.startAnimating()
        executeButton.isEnabled = false
        
        Task {
            do {
                let _ = try await tradingService.executeTrade(
                    symbol: stock.symbol,
                    type: tradeType,
                    quantity: quantity,
                    price: stock.currentPrice
                )
                
                await MainActor.run {
                    activityIndicator.stopAnimating()
                    executeButton.isEnabled = true
                    showSuccessAndDismiss()
                }
            } catch {
                await MainActor.run {
                    activityIndicator.stopAnimating()
                    executeButton.isEnabled = true
                    showError(error)
                }
            }
        }
    }
    
    private func showSuccessAndDismiss() {
        let alert = UIAlertController(title: "Success", message: "Trade executed successfully", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { [weak self] _ in
            self?.dismiss(animated: true)
        })
        present(alert, animated: true)
    }
    
    @objc private func closeTapped() {
        dismiss(animated: true)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    @MainActor
    private func showError(_ error: Error) {
        showAlert(title: "Error", message: error.localizedDescription)
    }
    
    private func formatCurrency(_ value: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: NSNumber(value: value)) ?? "$0.00"
    }
}

// MARK: - Watchlist View Controller

class WatchlistViewController: UIViewController {
    private let marketDataService = MarketDataService.shared
    private var cancellables = Set<AnyCancellable>()
    
    private let tableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .plain)
        tv.translatesAutoresizingMaskIntoConstraints = false
        tv.register(StockCell.self, forCellReuseIdentifier: "StockCell")
        return tv
    }()
    
    private let searchController = UISearchController(searchResultsController: nil)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupBindings()
        loadWatchlist()
        marketDataService.startRealtimeUpdates()
    }
    
    override func viewWillDisappear(_ animated: Bool) {
        super.viewWillDisappear(animated)
        if isMovingFromParent {
            marketDataService.stopRealtimeUpdates()
        }
    }
    
    private func setupUI() {
        title = "Watchlist"
        view.backgroundColor = .systemBackground
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .add, target: self, action: #selector(addStock))
        
        searchController.searchResultsUpdater = self
        searchController.obscuresBackgroundDuringPresentation = false
        searchController.searchBar.placeholder = "Search stocks"
        navigationItem.searchController = searchController
        definesPresentationContext = true
        
        view.addSubview(tableView)
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        tableView.delegate = self
        tableView.dataSource = self
    }
    
    private func setupBindings() {
        marketDataService.$watchlist
            .receive(on: DispatchQueue.main)
            .sink { [weak self] _ in
                self?.tableView.reloadData()
            }
            .store(in: &cancellables)
    }
    
    private func loadWatchlist() {
        Task {
            try? await marketDataService.fetchWatchlist()
        }
    }
    
    @objc private func addStock() {
        let alert = UIAlertController(title: "Add Stock", message: "Enter stock symbol", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Symbol"
            textField.autocapitalizationType = .allCharacters
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Add", style: .default) { [weak self, weak alert] _ in
            if let symbol = alert?.textFields?.first?.text?.uppercased(), !symbol.isEmpty {
                self?.addToWatchlist(symbol: symbol)
            }
        })
        present(alert, animated: true)
    }
    
    private func addToWatchlist(symbol: String) {
        Task {
            do {
                try await marketDataService.addToWatchlist(symbol: symbol)
            } catch {
                await showError(error)
            }
        }
    }
    
    @MainActor
    private func showError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension WatchlistViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return marketDataService.watchlist.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "StockCell", for: indexPath) as! StockCell
        let stock = marketDataService.watchlist[indexPath.row]
        cell.configure(with: stock)
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let stock = marketDataService.watchlist[indexPath.row]
        showTradeSheet(for: stock.symbol)
    }
    
    func tableView(_ tableView: UITableView, commit editingStyle: UITableViewCell.EditingStyle, forRowAt indexPath: IndexPath) {
        if editingStyle == .delete {
            let stock = marketDataService.watchlist[indexPath.row]
            Task {
                try? await marketDataService.removeFromWatchlist(symbol: stock.symbol)
            }
        }
    }
    
    private func showTradeSheet(for symbol: String) {
        let tradeVC = TradeViewController(symbol: symbol)
        let nav = UINavigationController(rootViewController: tradeVC)
        if let sheet = nav.sheetPresentationController {
            sheet.detents = [.medium(), .large()]
            sheet.prefersGrabberVisible = true
        }
        present(nav, animated: true)
    }
}

extension WatchlistViewController: UISearchResultsUpdating {
    func updateSearchResults(for searchController: UISearchController) {
        guard let query = searchController.searchBar.text, !query.isEmpty else {
            return
        }
        
        Task {
            try? await marketDataService.searchStocks(query: query)
        }
    }
}

